try {
    $excel = New-Object -ComObject Excel.Application
    $excel.Visible = $false
    $excel.DisplayAlerts = $false
    $wb = $excel.Workbooks.Open('C:\Users\Administrator\Desktop\形式发票模板00002.xlsx')
    foreach ($ws in $wb.Worksheets) {
        Write-Host \"=== Sheet: $($ws.Name) ===\"
