        $rows = $usedRange.Rows.Count
        $cols = $usedRange.Columns.Count
        Write-Host \"Rows: $rows, Cols: $cols\"
        for ($r = 1; $r -le $rows; $r++) {
            $rowData = @()
            for ($c = 1; $c -le $cols; $c++) {
                $cell = $ws.Cells.Item($r, $c)
                $coord = \"R${r}C${c}\"
                $val = $cell.Text
                $rowData += \"$coord=$val\"
            }
            Write-Host ($rowData -join ' | ')
        }
        Write-Host ''
    }
    $wb.Close($false)
    $excel.Quit()
} catch {
    Write-Host \"Error: $_\"
}
" 2>&1

