const fs = require('fs');
const base = 'C:/Users/Administrator/AppData/Local/Temp/pi_check/';

let ss = fs.readFileSync(base + 'xl/sharedStrings.xml', 'utf8');

// === EDITS ===

// 1. String 18: "1-7Days" → "45 Days"
ss = ss.replace(
  /(<si><t>1-7Days<\/t><\/si>)/,
  '<si><t>45 Days</t></si>'
);

// 2. String 29: Fix multiple typos
// "bank swift" → "bank SWIFT"
// "mail to sales ." → "mail to sales."
// "would not be unnecessarily delay" → "would not be unnecessarily delayed"
// "bank verifiration" → "bank verification"
let old29 = '<t>You are asked to send the copy of bank swift by mail to sales . Then, the shipment would not be unnecessarily delay due to the bank verifiration omitted.</t>';
let new29 = '<t>You are asked to send the copy of bank SWIFT by mail to sales. Then, the shipment would not be unnecessarily delayed due to the bank verification omitted.</t>';
ss = ss.replace(old29, new29);

// 3. String 33: Company name in footer
// Change "YIYANG LITTLE STAR GARMENT Co., Ltd." → "YIYANG XIAOXINGXING GARMENTS Co., Ltd."
// This is a rich text string, the company name is in the first <r> block
ss = ss.replace(
  /(<t xml:space="preserve">3\. ORIGIN IS CHINA AND MANUFACTURED BY )YIYANG LITTLE STAR GARMENT( Co\., Ltd\.   <\/t>)/,
  '$1YIYANG XIAOXINGXING GARMENTS$2'
);

// 4. String 34: Quotation validity → one month from now (May 19 → June 19, 2026)
ss = ss.replace(
  /(<si><t>)4\.QUOTATION VALIDITY: ONLY 2026-5-17\(FOR GOODS ONLY\)(<\/t><\/si>)/,
  '$14.QUOTATION VALIDITY: ONLY 2026-6-19(FOR GOODS ONLY)$2'
);

// 5. String 37: "Authorized Signaturer" → "Authorized Signatory"
// Also fix the full-width colon ：→ :
ss = ss.replace(
  /(<t>)Authorized Signaturer(<\/t>)/,
  '$1Authorized Signatory$2'
);
// Fix the full-width colon after 宋体 (in second <r>)
// Change "： " to ": " in the third <r> for the name
ss = ss.replace(
  /(<r><rPr><sz val="12"\/><rFont val="宋体"\/><charset val="134"\/><\/rPr><t>)：(<\/t><\/r>)/,
  '$1:$2'
);

fs.writeFileSync(base + 'xl/sharedStrings.xml', ss, 'utf8');
console.log('sharedStrings.xml updated successfully');

// Verify
let ss2 = fs.readFileSync(base + 'xl/sharedStrings.xml', 'utf8');
const siRegex = /<si>([\s\S]*?)<\/si>/g;
let match;
let idx = 0;
while ((match = siRegex.exec(ss2)) !== null) {
    const tRegex = /<t[^>]*>([\s\S]*?)<\/t>/g;
    let tMatch;
    const texts = [];
    while ((tMatch = tRegex.exec(match[1])) !== null) {
        texts.push(tMatch[1].replace(/&#10;/g, '\\n'));
    }
    if ([18, 29, 33, 34, 37].includes(idx)) {
        console.log(idx + ': ' + texts.join('').substring(0, 200));
    }
    idx++;
}
NODEEOF
node /tmp/edit_pi.js 2>&1

